### Change 1 — `src/routes/api.ts`: add `DELETE /api/subscriptions`

Insert a new block immediately **after** the GET handler's closing brace (after `api.ts:556`), mirroring its structure:

```ts
// DELETE /api/subscriptions { project, session, scope, targetId? } — unsubscribe one
// row from the Bridge "Subscribers" tab. Wraps removeSubscription (the panel was
// read-only; removal previously existed only as the MCP `unsubscribe` tool).
if (path === '/api/subscriptions' && req.method === 'DELETE') {
  try {
    const body = (await req.json()) as { project?: string; session?: string; scope?: string; targetId?: string };
    const project = body.project ? expandPath(body.project) : null;
    const { session, scope, targetId } = body;
    if (!project || !session || !scope) {
      return Response.json({ error: 'project, session, scope required' }, { status: 400 });
    }
    if (!['todo', 'epic', 'mission', 'project'].includes(scope)) {
      return Response.json({ error: `invalid scope "${scope}"` }, { status: 400 });
    }
    const { removeSubscription } = await import('../services/session-subscriptions');
    const removed = removeSubscription(project, session, scope as any, targetId);
    return Response.json({ ok: true, removed }, { headers: { 'Cache-Control': 'no-store' } });
  } catch (error: any) {
    return serverError(error);
  }
}
```

Notes: `expandPath` matches the GET route's project handling so the DELETE targets the same stored `project` value the GET returned. The scope allow-list mirrors the MCP tool (`setup.ts:2089`).

