### 1. `src/services/worker-ledger.ts` (edit) — uncapped burn aggregate
Add, next to `summarize`, a raw uncapped GROUP-BY (must NOT go through `queryLedger`'s 2000-row cap):

```ts
export interface BurnBySource {
  source: string;
  calls: number;
  inputTokens: number;
  outputTokens: number;
  cacheReadTokens: number;
  cacheCreationTokens: number;
  usd: number;
  unknownPrice: boolean;   // any row with knownPrice=0 in this source bucket
}

/** Uncapped per-source spend rollup over [since, now]. Best-effort → [] on error. */
export function getBurnBySource(opts: { project?: string; since?: number } = {}): BurnBySource[] {
  try {
    const d = openDb();
    const where: string[] = [];
    const params: unknown[] = [];
    if (opts.project) { where.push('project = ?'); params.push(opts.project); }
    if (opts.since != null) { where.push('ts >= ?'); params.push(opts.since); }
    const sql =
      `SELECT source,
              COUNT(*) AS calls,
              COALESCE(SUM(inputTokens),0) AS inputTokens,
              COALESCE(SUM(outputTokens),0) AS outputTokens,
              COALESCE(SUM(cacheReadTokens),0) AS cacheReadTokens,
              COALESCE(SUM(cacheCreationTokens),0) AS cacheCreationTokens,
              COALESCE(SUM(costUsd),0) AS usd,
              MIN(knownPrice) AS minKnown
       FROM worker_ledger${where.length ? ' WHERE ' + where.join(' AND ') : ''}
       GROUP BY source ORDER BY calls DESC`;
    const rows = d.query(sql).all(...(params as never[])) as Array<BurnBySource & { minKnown: number }>;
    return rows.map((r) => ({ ...r, unknownPrice: r.minKnown === 0 }));
  } catch { return []; }
}
```
(`openDb` is module-private here — this is why the aggregate lives in `worker-ledger.ts`, re-exported below.)

