import { recordPhase, getBurnBySource, type BurnBySource } from './worker-ledger.js';
import { estimateCostUsd, knownPricing } from '../agent/worker-core/cost.js';

export interface SpendUsage {
  inputTokens?: number; outputTokens?: number;
  cacheReadTokens?: number; cacheCreationTokens?: number;
  costUsd?: number; numTurns?: number;
}
export interface SpendEntry {
  project: string;
  source: string;                 // conductor|summary|triage|digest|forge|planner|consult-grok|consult-codex|node…
  provider?: string;              // 'claude' | 'grok' | 'xai' | 'openai' | 'anthropic'
  model?: string;
  usage?: SpendUsage;
  leafId?: string | null;
  todoId?: string | null;
  epicId?: string | null;
  session?: string;
}

/** Record ONE non-leaf LLM call's spend into worker_ledger, tagged by source.
 *  USD: prefer the CLI's own costUsd; else estimate tokens×MODEL_PRICING (Max plan).
 *  Best-effort — never throws (recordPhase already swallows, but guard the estimate too). */
export function recordSpend(e: SpendEntry, now: number = Date.now()): number | null {
  try {
    const u = e.usage ?? {};
    const known = knownPricing(e.model);
    const usd = (u.costUsd && u.costUsd > 0)
      ? u.costUsd
      : estimateCostUsd(e.model, { inputTokens: u.inputTokens, outputTokens: u.outputTokens });
    return recordPhase({
      project: e.project, todoId: e.todoId ?? e.leafId ?? '-', epicId: e.epicId ?? null,
      session: e.session ?? e.source, phase: 'spend',
      provider: e.provider ?? 'claude', model: e.model ?? '', source: e.source,
      inputTokens: u.inputTokens ?? 0, outputTokens: u.outputTokens ?? 0,
      cacheReadTokens: u.cacheReadTokens ?? 0, cacheCreationTokens: u.cacheCreationTokens ?? 0,
      costUsd: usd, knownPrice: known, steps: u.numTurns ?? 0,
      nodeKind: null, nodesSpent: null, leafId: e.leafId ?? null,
    }, now);
  } catch { return null; }
}

export { getBurnBySource, type BurnBySource };
```

