```ts
import { getBurnBySource } from './spend-ledger.js';
import { queryLedger } from './worker-ledger.js';
import { createEscalation } from './supervisor-store.js';

/** Leaf/build spend is EXPECTED (tracked by mission-cost) — exempt from the leak alarm.
 *  Everything else (conductor/summary/triage/digest/forge/planner/consult-*) is a candidate leak. */
export const BUILD_SOURCES = new Set(['node', 'leaf', 'implement', 'review', 'verify', 'blueprint', 'research', 'fix', 'plan']);
export const BURN_WATCH_WINDOW_MS = 60 * 60_000;   // 1h rolling window
export const SOURCE_CALL_CEILING = 40;             // per-source calls/window before it's suspicious
export const BURN_WATCH_INTERVAL_MS = 5 * 60_000;  // throttle: at most once / 5min / project

let lastBurnWatchAt: number | null = null;
export function shouldRunBurnWatchPass(now: number = Date.now()): boolean {
  if (lastBurnWatchAt !== null && now - lastBurnWatchAt < BURN_WATCH_INTERVAL_MS) return false;
  lastBurnWatchAt = now; return true;
}
export function _resetBurnWatchThrottle(): void { lastBurnWatchAt = null; }

/** Accepted-work signal: any leaf that reached an 'accepted' terminal outcome in the window. */
export function countAcceptedWork(project: string, since: number): number {
  return queryLedger({ project, since, limit: 2000 }).filter((r) => r.leafOutcome === 'accepted').length;
}

export interface BurnWatchDeps {
  now?: number;
  burnBySource?: typeof getBurnBySource;
  acceptedWork?: (project: string, since: number) => number;
  raise?: typeof createEscalation;
}

/** One throttled leak-watch pass. Raises a deduped, operator-gated 'token-burn' escalation
 *  when a NON-build source exceeds SOURCE_CALL_CEILING with ZERO accepted work in the window.
 *  Keys on CALL COUNT (plan-independent — Max plan omits USD). Returns the raised source (or null). */
export function runBurnWatchPass(project: string, deps: BurnWatchDeps = {}): string | null {
  const now = deps.now ?? Date.now();
  const since = now - BURN_WATCH_WINDOW_MS;
  const rows = (deps.burnBySource ?? getBurnBySource)({ project, since });
  const accepted = (deps.acceptedWork ?? countAcceptedWork)(project, since);
  if (accepted > 0) return null;               // real work is landing — spend is legitimate
  const leak = rows.find((r) => !BUILD_SOURCES.has(r.source) && r.calls >= SOURCE_CALL_CEILING);
  if (!leak) return null;
  (deps.raise ?? createEscalation)({
    project, session: 'burn-watch',            // stable session → createEscalation dedups the open card
    kind: 'token-burn',
    questionText: `Token-burn leak: source '${leak.source}' made ${leak.calls} calls in the last hour with no accepted work. Investigate/stop the loop.`,
    operatorGated: true,
  });
  return leak.source;
}
```

