```ts
/** Compose {@link parseDiffContract} + {@link validateContractForKind} against the contract's
 *  OWN declared leafKind — the one testable decision behind the bounded blueprint-underspec
 *  repair wired in leaf-executor.ts. FAIL-SAFE: a source with no parseable v2 contract (a v1-only
 *  manifest, the common case today) ⇒ { underspecified: false }, so this repair only bites
 *  blueprints that opted into a v2 DiffContract. Never throws (parseDiffContract never throws). */
export function evaluateContractUnderspecification(
  ...sources: Array<string | undefined>
):
  | { underspecified: true; missingField: DiffRequirementKind; leafKind: DiffLeafKind }
  | { underspecified: false } {
  const contract = parseDiffContract(...sources);
  if (!contract) return { underspecified: false };
  const verdict = validateContractForKind(contract, contract.leafKind);
  if (verdict.underspecified) {
    return { underspecified: true, missingField: verdict.missingField, leafKind: contract.leafKind };
  }
  return { underspecified: false };
}
```

